record.field:
setting_set = env['ir.config_parameter'].sudo().get_param('construction_configuration.enable_progress_management', '0') != '0'
if not (module := env['ir.module.module'].search([('name', '=', 'construction_progress_management')], limit=1)) and not setting_set and record.x_setting_progress_management:
    action_window = env['ir.module.module'].with_context({'module_name': 'construction_progress_management'}).button_immediate_install_app()
    env['base.import.module'].with_context(action_window.get('context')).browse(action_window['res_id']).import_module()
    env['ir.config_parameter'].sudo().set_param('construction_configuration.enable_progress_management', '1')
    record['module_industry_fsm_report'] = True
elif module and setting_set and not record.x_setting_progress_management:
    line_numbering_module = env['ir.module.module'].search([('name', '=', 'construction_line_numbering')], limit=1)
    if line_numbering_module and not env['ir.module.module'].search_count([('dependencies_id.name', '=', 'construction_line_numbering')], limit=1):
        (module + line_numbering_module).button_immediate_uninstall()
    else: module.button_immediate_uninstall()
    env['ir.config_parameter'].sudo().set_param('construction_configuration.enable_progress_management', '0')

setting_set = env['ir.config_parameter'].sudo().get_param('construction_configuration.enable_show_line_numbering', '0') != '0'
